/**
 * Material Symbols font set identifiers.
 *
 * These values correspond to the CSS class generated by the Google Fonts
 * stylesheet. The active value must match the font family loaded in the
 * application (e.g., via a `<link>` tag in `index.html`, Storybook's
 * `preview-head.html`, or any other font-loading mechanism).
 *
 * The fontSet is resolved by `TbxMatFontIconService` through a precedence chain:
 * 1. Explicit constructor argument — `super('material-symbols-sharp')`
 * 2. `TBX_MAT_FONT_ICON_DEFAULT_FONT_SET` injection token
 * 3. `MAT_ICON_DEFAULT_OPTIONS.fontSet` from Angular Material
 *
 * See: https://fonts.google.com/icons
 */
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_ROUNDED = 'material-symbols-rounded';
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_OUTLINED = 'material-symbols-outlined';
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_SHARP = 'material-symbols-sharp';
